const e={"PT-1":{title:"Policy and Procedures",body:"[ORG] has developed, documented, and disseminated a PII Processing and Transparency Policy addressing purpose, scope, roles, responsibilities, and compliance with the Privacy Act and applicable federal privacy laws. Reviewed annually. The designated privacy official is responsible for implementing PII processing and transparency controls for [SYSTEM].",tools:[]},"PT-2":{title:"Authority to Process Personally Identifiable Information",body:"[ORG] determines and documents the authority that permits the processing of PII for [SYSTEM]. Processing authority is documented in the System of Records Notice (SORN) if required, Privacy Impact Assessment (PIA), and SSP. PII is processed only for authorized purposes consistent with the documented authority. The privacy official reviews processing authority annually and when [SYSTEM] purpose changes.",tools:[]},"PT-2(1)":{title:"Authority to Process PII | Data Tagging",body:"[ORG] attaches data tags to PII processed by [SYSTEM] to automate tracking of authority to process. Data classification and handling labels are applied to [SYSTEM] data consistent with CUI requirements. [TOOL:paloalto] DLP policies use data tags to enforce handling restrictions. Data tagging procedures are documented and personnel are trained on tagging requirements.",tools:["paloalto"]},"PT-3":{title:"Personally Identifiable Information Processing Purposes",body:"[ORG] identifies and documents the purpose(s) for which PII is processed by [SYSTEM]. PII processing purposes are documented in the PIA and SSP. PII is collected only for the minimum necessary to fulfill the stated purposes. Personnel are informed of PII processing purposes through privacy notices. The privacy official reviews PII processing purposes annually and upon significant system changes.",tools:[]},"PT-3(1)":{title:"PII Processing Purposes | Data Tagging",body:"[ORG] attaches data tags to PII to automate the tracking of [SYSTEM] processing purposes. Data tags indicate the purpose for which PII was collected and permitted uses. [TOOL:paloalto] DLP policies enforce purpose-based handling restrictions. Data purpose tags are reviewed and updated when processing purposes change. Personnel are trained on data purpose tagging requirements.",tools:["paloalto"]},"PT-4":{title:"Consent",body:"[ORG] implements consent mechanisms for the processing of PII by [SYSTEM] where consent is required. Where consent is the legal authority for processing, informed consent is obtained before PII collection. Consent records are maintained and retrievable. Personnel are informed of their rights regarding consent withdrawal. The privacy official reviews consent mechanisms annually for legal compliance.",tools:[]},"PT-5":{title:"Privacy Notice",body:"[ORG] provides privacy notice at the point of PII collection for [SYSTEM]. Privacy notices inform individuals of: the authority for collection, purpose(s) of collection, routine uses, whether disclosure is mandatory or voluntary, and consequences of not providing PII. Privacy notices comply with the Privacy Act and federal privacy guidance. [ISSO] coordinates with the privacy official to ensure privacy notices are displayed at system entry points.",tools:[]},"PT-6":{title:"System of Records Notice",body:"[ORG] publishes a System of Records Notice (SORN) in the Federal Register for [SYSTEM] where required by the Privacy Act. The SORN describes: system name and number, category of individuals, categories of records, routine uses, policies and practices for storage and retrieval, access controls, retention and disposal, and administrator and address. The privacy official coordinates SORN publication and updates. SORN is reviewed and updated when system changes affect covered records.",tools:[]},"PT-7":{title:"Specific Categories of Personally Identifiable Information",body:"[ORG] applies additional processing conditions for specific categories of PII processed by [SYSTEM] including: health information, financial information, and other sensitive PII categories. Additional protections include: heightened access controls in [TOOL:ad], enhanced audit logging in [TOOL:splunk], and specific handling and disclosure restrictions. Personnel with access to sensitive PII categories receive specialized training on handling requirements.",tools:["ad","splunk"]},"PT-8":{title:"Computer Matching Requirements",body:"[ORG] implements the computer matching requirements of the Privacy Act for [SYSTEM] where applicable. Where [SYSTEM] performs computer matching, a Computer Matching Agreement (CMA) is established. The [ISSM] coordinates CMA implementation with the privacy official. Computer matching activities are audited via [TOOL:splunk]. Matching results are protected with controls equivalent to source records. The privacy official reviews computer matching compliance annually.",tools:["splunk"]}};export{e as default};
